import React, { useState, useEffect } from 'react';
import './ClientForm.css';

const ClientForm = ({ selectedClient, onSuccess }) => {
  const [formData, setFormData] = useState({
    nomCli: '',
    prenomCli: '',
    adressCli: '',
    telCli: '',
    sexe: ''
  });

  useEffect(() => {
    if (selectedClient) {
      setFormData(selectedClient);
    } else {
      resetForm();
    }
  }, [selectedClient]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const resetForm = () => {
    setFormData({
      nomCli: '',
      prenomCli: '',
      adressCli: '',
      telCli: '',
      sexe: ''
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const method = selectedClient ? 'PUT' : 'POST';
    const url = selectedClient
      ? `http://localhost:3001/clients/${selectedClient.codeCli}`
      : 'http://localhost:3001/clients';

    try {
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });

      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      if (!selectedClient) resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      alert(err.message);
    }
  };

  const handleDelete = async () => {
    if (!selectedClient) return;

    const confirmDelete = window.confirm('Supprimer ce client ?');
    if (!confirmDelete) return;

    try {
      const res = await fetch(`http://localhost:3001/clients/${selectedClient.codeCli}`, {
        method: 'DELETE'
      });

      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      alert(err.message);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="client-form">
      <input
        name="nomCli"
        placeholder="Nom"
        value={formData.nomCli}
        onChange={handleChange}
        required
      />
      <input
        name="prenomCli"
        placeholder="Prénom"
        value={formData.prenomCli}
        onChange={handleChange}
        required
      />
      <input
        name="adressCli"
        placeholder="Adresse"
        value={formData.adressCli}
        onChange={handleChange}
        required
      />
      <input
        name="telCli"
        placeholder="Téléphone"
        value={formData.telCli}
        onChange={handleChange}
        required
      />
      <input
        name="sexe"
        placeholder="Sexe (H/F)"
        value={formData.sexe}
        onChange={handleChange}
        required
      />

      <button type="submit">
        {selectedClient ? 'Modifier' : 'Ajouter'}
      </button>
      {selectedClient && (
        <button type="button" onClick={handleDelete}>
          Supprimer
        </button>
      )}
    </form>
  );
};

export default ClientForm;
